class Solution {
public:
    int findPairs(vector<int>& nums, int k) {
        if (k < 0) {
            return 0;
        }
        unordered_set<int> result, lookup;
        for (const auto& num : nums) {
            if (lookup.count(num - k)) {
                result.emplace(num - k);
            }
            if (lookup.count(num + k)) {
                result.emplace(num);
            }
            lookup.emplace(num);
        }
        return result.size();
    }
};

# Time:  O(n)
# Space: O(n)

class Solution(object):
    def findPairs(self, nums, k):
        """
        :type nums: List[int]
        :type k: int
        :rtype: int
        """
        if k < 0: return 0
        result, lookup = set(), set()
        for num in nums:
            if num-k in lookup:
                result.add(num-k)
            if num+k in lookup:
                result.add(num)
            lookup.add(num)
        return len(result)
